const metrics = $('GET Metrics').first().json;
const postsRaw = $('GET Posts').first().json;
const hashtagsRaw = $('GET Hashtags').first().json;
const accountsRaw = $('GET Accounts').first().json;

const allPosts = postsRaw?.results || postsRaw?.posts || (Array.isArray(postsRaw) ? postsRaw : []);
const topPosts = allPosts.slice(0, 8).map(p => ({
  account: p.account_username || p.username || 'unknown',
  caption: String(p.caption || '').substring(0, 200),
  likes: p.like_count || 0,
  comments: p.comment_count || 0,
  views: p.video_view_count || 0
}));

const allAccounts = accountsRaw?.results || accountsRaw?.accounts || (Array.isArray(accountsRaw) ? accountsRaw : []);
const accountData = allAccounts.map(a => ({
  username: a.username || '',
  followers: a.follower_count || 0
}));

const ashira = accountData.find(a => a.username.toLowerCase().includes('ashira'));
const today = new Date().toISOString().split('T')[0];

return [{
  json: {
    snapshot: {
      snapshot_date: today,
      days_range: 30,
      accounts: JSON.stringify(accountData),
      metrics: JSON.stringify(metrics),
      posts: JSON.stringify(topPosts),
      hashtags: JSON.stringify(hashtagsRaw),
      related: JSON.stringify([]),
      api_status: JSON.stringify({ fetched_at: new Date().toISOString() })
    },
    analysisInput: {
      date: today,
      ashira_followers: ashira?.followers || 242,
      accounts: accountData,
      top_posts: topPosts,
      hashtags: Array.isArray(hashtagsRaw?.results) ? hashtagsRaw.results.map(h => h.hashtag) : []
    }
  }
}];

const mergeData = $('Merge y Limpiar').first().json;
const snapshotArr = $('Guardar Snapshot').first().json;
const prevArr = $('Análisis Anterior').first().json;

const snapshotResult = Array.isArray(snapshotArr) ? snapshotArr[0] : snapshotArr;
const prev = Array.isArray(prevArr) ? prevArr[0] : null;

const input = { ...mergeData.analysisInput };
if (prev) {
  input.analisis_anterior = {
    fecha: prev.analysis_date,
    tendencia: prev.trend,
    insight_previo: JSON.parse(prev.competitive_summary || '{}').insight_principal
  };
}

const sys = 'Eres analista de marketing para ASHIRA. Genera estrategias NUEVAS en JSON...';
return [{ json: { systemPrompt: sys, promptInput: JSON.stringify(input), snapshotId: snapshotResult?.id } }];

const cr = $('Claude Haiku').item.json;
const pd = $('Construir Prompt').item.json;

let txt = '';
if (cr?.content?.[0]?.text) txt = cr.content[0].text;

const first = txt.indexOf('{');
const last = txt.lastIndexOf('}');
const cleaned = (first !== -1 && last !== -1) ? txt.substring(first, last + 1) : '{}';

let a = {};
try { a = JSON.parse(cleaned); } catch(e) { a = { trend: 'estancado' }; }

const it = cr?.usage?.input_tokens || 0;
const ot = cr?.usage?.output_tokens || 0;
const cost = (it / 1000000 * 0.8) + (ot / 1000000 * 4);

return [{ json: {
  analysis_date: new Date().toISOString().split('T')[0],
  snapshot_id: pd.snapshotId,
  competitive_summary: JSON.stringify(a.competitive_summary || {}),
  strategy_recepcionista: JSON.stringify(a.strategy_recepcionista || []),
  strategy_medico_independiente: JSON.stringify(a.strategy_medico_independiente || []),
  strategy_director_clinica: JSON.stringify(a.strategy_director_clinica || []),
  strategy_paciente: JSON.stringify(a.strategy_paciente || []),
  strategy_especialista: JSON.stringify(a.strategy_especialista || []),
  content_recommendations: JSON.stringify(a.content_recommendations || []),
  content_insights: JSON.stringify(a.content_insights || {}),
  hashtag_strategy: JSON.stringify(a.content_insights?.hashtags_recomendados || []),
  changes_vs_previous: JSON.stringify(a.changes_vs_previous || []),
  trend: a.trend || 'estancado',
  tokens_used: it + ot,
  analysis_cost_usd: parseFloat(cost.toFixed(6)),
  model_version: 'claude-3-5-haiku-latest'
} }];
